    name: "BookingsController_2024_08_13_rescheduleBooking",
    description: `Reschedule a booking or seated booking

    <Note>Please make sure to pass in the cal-api-version header value as mentioned in the Headers section. Not passing the correct value will default to an older version of this endpoint.</Note>
    `,
    inputSchema: {"type":"object","properties":{"cal-api-version":{"type":"string","default":"2024-08-13","description":"Must be set to 2024-08-13. If not set to this value, the endpoint will default to an older version."},"bookingUid":{"type":"string"},"x-cal-secret-key":{"type":"string","description":"For platform customers - OAuth client secret key"},"x-cal-client-id":{"type":"string","description":"For platform customers - OAuth client ID"},"requestBody":{"oneOf":[{"type":"object","properties":{"start":{"type":"string","description":"Start time in ISO 8601 format for the new booking","example":"2024-08-13T10:00:00Z"},"rescheduledBy":{"type":"string","description":"Email of the person who is rescheduling the booking - only needed when rescheduling a booking that requires a confirmation.\nIf event type owner email is provided then rescheduled booking will be automatically confirmed. If attendee email or no email is passed then the event type\nowner will have to confirm the rescheduled booking."},"reschedulingReason":{"type":"string","example":"User requested reschedule","description":"Reason for rescheduling the booking"},"emailVerificationCode":{"type":"string","description":"Email verification code required when event type has email verification enabled.","example":"123456"}},"required":["start"]},{"type":"object","properties":{"start":{"type":"string","description":"Start time in ISO 8601 format for the new booking","example":"2024-08-13T10:00:00Z"},"rescheduledBy":{"type":"string","description":"Email of the person who is rescheduling the booking - only needed when rescheduling a booking that requires a confirmation.\nIf event type owner email is provided then rescheduled booking will be automatically confirmed. If attendee email or no email is passed then the event type\nowner will have to confirm the rescheduled booking."},"seatUid":{"type":"string","example":"3be561a9-31f1-4b8e-aefc-9d9a085f0dd1","description":"Uid of the specific seat within booking."},"emailVerificationCode":{"type":"string","description":"Email verification code required when event type has email verification enabled.","example":"123456"}},"required":["start","seatUid"]}],"description":"Accepts different types of reschedule booking input: Reschedule Booking (Option 1) or Reschedule Seated Booking (Option 2). If you're rescheduling a seated booking as org admin of booking host, pass booking input for Reschedule Booking (Option 1) along with your access token in the request header.\n\n      If you are rescheduling a seated booking for an event type with 'show attendees' disabled, then to retrieve attendees in the response either set 'show attendees' to true on event type level or\n      you have to provide an authentication method of event type owner, host, team admin or owner or org admin or owner."}},"required":["cal-api-version","bookingUid","requestBody"]},
